# vault/policies/genai-ci.hcl
# Policy for CI jobs running tests against staging

path "secret/data/genai/staging/*" {
  capabilities = ["read"]
}

path "secret/data/genai/ci/*" {
  capabilities = ["read"]
}

# Deny prod paths explicitly (belt-and-suspenders)
path "secret/data/genai/prod/*" {
  capabilities = ["deny"]
}

# vault/policies/genai-deploy.hcl
# Policy for deploy jobs writing to prod

path "secret/data/genai/prod/*" {
  capabilities = ["read"]
}

path "secret/data/genai/staging/*" {
  capabilities = ["read"]
}

# Dynamic AWS creds for EKS deploy role
path "aws/creds/genai-deploy-role" {
  capabilities = ["read"]
}

# vault/policies/genai-eval.hcl
# Eval pipeline: access evaluation-tier API keys only

path "secret/data/genai/eval/openai/api-key" {
  capabilities = ["read"]
}

path "secret/data/genai/eval/anthropic/api-key" {
  capabilities = ["read"]
}

# Read eval dataset bucket credentials
path "secret/data/genai/eval/s3-eval-datasets" {
  capabilities = ["read"]
}

# Deny prod, staging, and CI paths
path "secret/data/genai/prod/*" {
  capabilities = ["deny"]
}
path "secret/data/genai/staging/*" {
  capabilities = ["deny"]
}
